
import { describe, it, expect } from 'vitest';
import { spawnCulturalAttractor, resolvePeacefulQuest } from '../void-quests';
import { createObserver } from '../void-game-engine';

describe('void-quests', () => {
  it('spawn and resolve a peace quest with diversity', () => {
    const quest = spawnCulturalAttractor(1, 10, -10, 0, 'diversity_affirmation');
    
    const obs1 = { ...createObserver('d1', 1, 'mystic', 'scientist', 'boson'), coordinate: quest.targetCoordinate };
    const obs2 = { ...createObserver('d2', 2, 'nihilist', 'builder', 'fermion'), coordinate: quest.targetCoordinate };
    
    expect(quest.requiredDiversity).toBe(1); // 1 + Math.floor(1 / 2) -> 1
    
    const result = resolvePeacefulQuest([obs1, obs2], quest);
    expect(result.resolvedQuest.isResolved).toBe(true);
    expect(result.states[0].wisdom).toBeGreaterThan(obs1.wisdom);
  });
});
